local LDefenceWarBaseCtrl = LXImport(".LDefenceWarBaseCtrl")

---@class LDefenceWarObjsCtrl:LDefenceWarBaseCtrl
local LDefenceWarObjsCtrl = LxClass("LDefenceWarObjsCtrl", LDefenceWarBaseCtrl)
-----------------------------------------------------------------
local table               = table
local pairs               = pairs
local ipairs              = ipairs
local string              = string
local math                = math
local tonumber            = tonumber

local LDefenceWarObj      = LXImport("..Object.LDefenceWarObj")

-----------------------------------------------------------------
function LDefenceWarObjsCtrl:LDefenceWarObjsCtrl()
    -- gModelDefenceWar
    self._model = gModelDefenceWar

    -- 对象列表
    self._objMap = {}

    -- 对象索引
    self._objIndex = 0

    -- 准备生成怪物列表
    self._readyCreateMonsterList = {}

    -- 正在加载怪物的最大数量
    self._maxLoadingMonsterCount = 1

    -- 刷怪间隔
    self._createMonsterInterval = 0.3

    -- 下一个刷怪时间
    self._nextCreateMonsterTime = 0

    -- 正在加载怪物的数量
    self._loadingMonsterCount = 0

    -- 怪物达到此线才算进入技能范围
    self._skillRangeLine = gModelDefenceWar:GetSkillAttackHeight()
end

-- 销毁
function LDefenceWarObjsCtrl:OnDestroy()
    for i, obj in pairs(self._objMap) do
        obj:Destroy()
    end
    self._objMap = {}
end

-- 销毁一个对象
function LDefenceWarObjsCtrl:DestroyObj(key)
    if self._objMap[key] then
        self._objMap[key]:Destroy()
        self._objMap[key] = nil
    end
end

-- 初始化
function LDefenceWarObjsCtrl:Init()

end

-- Update
function LDefenceWarObjsCtrl:Update(dt)
    if self:IsDestroy() then
        return
    end

    for i, obj in pairs(self._objMap) do
        obj:Update(dt)
    end

    self._nextCreateMonsterTime = self._nextCreateMonsterTime - dt
    if self._nextCreateMonsterTime <= 0 then
        self:UpdateCreateObj()
    end
end

-- 暂停
function LDefenceWarObjsCtrl:OnPauseGame()
    for i, obj in pairs(self._objMap) do
        obj:OnPauseGame()
    end
end

-- 恢复
function LDefenceWarObjsCtrl:OnResumeGame()
    for i, obj in pairs(self._objMap) do
        obj:OnResumeGame()
    end
end

-- 怪物数量
function LDefenceWarObjsCtrl:GetMonsterCount()
    local count = 0
    for i, obj in pairs(self._objMap) do
        if not obj:IsDead() then
            count = count + 1
        end
    end

    return count
end

-- 准备生产怪物数量
function LDefenceWarObjsCtrl:GetReadyCreateMonsterCount()
    return #self._readyCreateMonsterList
end

-- 弹出对象索引
function LDefenceWarObjsCtrl:PopObjIndex()
    self._objIndex = self._objIndex + 1
    return self._objIndex
end

-- 弹出对象
function LDefenceWarObjsCtrl:PopObj()
    if not self._objNode then
        local root    = self:GetMap():GetMapTrans()
        local trans   = CS.FindTrans(root, "LayerRoot/ObjRoot/MonsterNode")
        self._objNode = trans.gameObject
    end

    local parent = self:GetParent()
    local obj = LxUnity.InstantObject(self._objNode)
    local trans = obj.transform
    trans:SetParent(parent, false)
    CS.ShowObject(obj, true)
    return trans
end

-- 获取对象父节点
function LDefenceWarObjsCtrl:GetParent()
    if not self._parent then
        local root   = self:GetMap():GetMapTrans()
        self._parent = CS.FindTrans(root, "LayerRoot/MonsterRoot")
    end
    return self._parent
end

-- 准备生成怪物
function LDefenceWarObjsCtrl:ReadyCreateMonster(dataList)
    for _, tab in ipairs(dataList) do
        table.insert(self._readyCreateMonsterList, tab)
    end
end

-- 创建对象
function LDefenceWarObjsCtrl:CreateObj(param)
    local obj                 = LDefenceWarObj:New(self)
    local index               = self:PopObjIndex()
    local trans               = self:PopObj()
    local data                = {
        index = index,
        trans = trans,
        monsterRefId = param.monsterRefId,
        groupRefId = param.groupRefId,
        pos = param.pos,
    }

    self._loadingMonsterCount = self._loadingMonsterCount + 1
    obj:SetLoadedCallback(function()
        self._loadingMonsterCount = self._loadingMonsterCount - 1
    end)
    obj:Init(data)
    self._objMap[index] = obj
end

-- 生成对象
function LDefenceWarObjsCtrl:UpdateCreateObj()
    if self._loadingMonsterCount >= self._maxLoadingMonsterCount then
        return
    end

    local list = self._readyCreateMonsterList
    if #list == 0 then
        return
    end

    for i = 1, self._maxLoadingMonsterCount - self._loadingMonsterCount do
        local param = table.remove(list, 1)
        if not param then
            break
        end
        self._nextCreateMonsterTime = self._createMonsterInterval
        self:CreateObj(param)
    end
end

-- true: 表示有怪物进入技能范围
function LDefenceWarObjsCtrl:HasMonsterInSKillRange()
    local skillH = self._skillRangeLine
    for i, obj in pairs(self._objMap) do
        if obj:IsValid() then
            local trans = obj:GetTransform()
            local pos = trans.localPosition
            if pos.y < skillH then
                return true
            end
        end
    end
    return false
end

-- 获取单体技能目标列表
function LDefenceWarObjsCtrl:GetSingleSkillTargetList(targetNum)
    local list = {}
    for i, obj in pairs(self._objMap) do
        if obj:IsValid() then
            local trans = obj:GetTransform()
            local pos = trans.localPosition
            if pos.y < self._skillRangeLine then
                table.insert(list, { obj = obj, pos = pos })
            end
        end
    end

    local targetList = {}
    if #list < targetNum then
        for k, v in ipairs(list) do
            table.insert(targetList, v.obj)
        end
    else
        table.sort(list, function(a, b)
            if a.pos.y ~= b.pos.y then
                return a.pos.y < b.pos.y
            end
            return a.obj:GetIndex() < b.obj:GetIndex()
        end)

        for i = 1, targetNum do
            table.insert(targetList, list[i].obj)
        end
    end

    return targetList
end

-- 获取释放技能位置和目标列表
function LDefenceWarObjsCtrl:GetDoSkillPosAndTargetList(skillRef)
    local posMap = {}
    local posY = 9999
    local targetPos = nil
    for i, obj in pairs(self._objMap) do
        if obj:IsValid() then
            local trans = obj:GetTransform()
            local pos = trans.localPosition
            posMap[obj] = pos
            if pos.y < posY then
                posY = pos.y
                targetPos = pos
            end
        end
    end

    local skillRange = skillRef.skillrange
    local range = skillRange * skillRange
    local range2 = (skillRange * 2) * (skillRange * 2)

    local rangeObjMap = {}
    local rangeObjMap2 = {}
    local targetObjList = {}
    for obj, pos in pairs(posMap) do
        if self:IsInRange(targetPos, pos, range) then
            rangeObjMap[obj] = pos
            table.insert(targetObjList, obj)
        elseif self:IsInRange(pos, targetPos, range2) then
            rangeObjMap2[obj] = pos
        end
    end

    local centerPos = self:GetCenterPos(rangeObjMap)
    for obj, pos in pairs(rangeObjMap2) do
        if self:IsInRange(centerPos, pos, range) then
            table.insert(targetObjList, obj)
        end
    end
    return centerPos, targetObjList
end

-- 获取释放技能伤害目标列表
function LDefenceWarObjsCtrl:GetDoSkillDamageTargetList(skillRef, pos)
    local targetObjList = {}

    local skillRange = skillRef.skillrange
    local range = skillRange * skillRange

    for i, obj in pairs(self._objMap) do
        if obj:IsValid() then
            local trans = obj:GetTransform()
            local posB = trans.localPosition
            if self:IsInRange(pos, posB, range) then
                table.insert(targetObjList, obj)
            end
        end
    end
    return targetObjList
end

-- posA: 圆心
-- posB: 目标点
-- r2: 半径的平方
-- true: 表示posB点在圆心posA的r2半径范围内
function LDefenceWarObjsCtrl:IsInRange(posA, posB, r2)
    local dis = (posA.x - posB.x) * (posA.x - posB.x) + (posA.y - posB.y) * (posA.y - posB.y)
    return r2 >= dis
end

-- 获取多个坐标的中心点
function LDefenceWarObjsCtrl:GetCenterPos(rangeObjMap)
    local minX, maxX, minY, maxY

    for obj, pos in pairs(rangeObjMap) do
        if not minX then
            minX = pos.x
            maxX = pos.x
            minY = pos.y
            maxY = pos.y
        else
            minX = math.min(minX, pos.x)
            maxX = math.max(maxX, pos.x)
            minY = math.min(minY, pos.y)
            maxY = math.max(maxY, pos.y)
        end
    end
    return Vector3((minX + maxX) / 2, math.max(0, (minY + maxY) / 2), 0)
end

-- 增加buff
function LDefenceWarObjsCtrl:AddBuff(data)
    for _, obj in ipairs(data.targetList) do
        obj:AddBuff(data)
    end
end

-- 移除buff
function LDefenceWarObjsCtrl:RemoveBuff(heroId, skillId)
    for index, obj in ipairs(self._objMap) do
        obj:RemoveBuff(heroId, skillId)
    end
end

return LDefenceWarObjsCtrl
